a = list(map(int, input().split()))


# check if all elements in the list are even
def is_all_even(lst):
    for num in lst:
        if num % 2 != 0:
            return False
    return True


# check if the first and last element in the list are odd
def is_first_last_odd(lst):
    return lst[0] % 2 != 0 and lst[-1] % 2 != 0


# check if the list can be divided into an odd number of non-empty subsegments
def can_divide_into_odd_subsegments(lst):
    if len(lst) % 2 == 0:
        return False
    if is_all_even(lst):
        return False
    if is_first_last_odd(lst):
        return True
    return False


# main function
if can_divide_into_odd_subsegments(a):
    print("Yes")
else:
